742:       serverFactoryContext(), stats_store_, thread_local_, http_context_,
743:       [this]() -> Network::DnsResolverSharedPtr { return this->getOrCreateDnsResolver(); },
744:       *ssl_context_manager_, *secret_manager_, quic_stat_names_, *this);
745: 
746:   // Now the configuration gets parsed. The configuration may start setting
747:   // thread local data per above. See MainImpl::initialize() for why ConfigImpl
748:   // is constructed as part of the InstanceBase and then populated once
749:   // cluster_manager_factory_ is available.
750:   RETURN_IF_NOT_OK(config_.initialize(bootstrap_, *this, *cluster_manager_factory_));
751: 
752:   // Instruct the listener manager to create the LDS provider if needed. This must be done later
