40: void ConnectionHandlerImpl::addListener(absl::optional<uint64_t> overridden_listener,
41:                                         Network::ListenerConfig& config, Runtime::Loader& runtime,
42:                                         Random::RandomGenerator& random) {
43:   if (overridden_listener.has_value()) {
44:     ActiveListenerDetailsOptRef listener_detail =
45:         findActiveListenerByTag(overridden_listener.value());
46:     ASSERT(listener_detail.has_value());
47:     listener_detail->get().invokeListenerMethod(
48:         [&config](Network::ConnectionHandler::ActiveListener& listener) {
49:           listener.updateListenerConfig(config);
50:         });
51:     return;
52:   }
53: 
54:   auto details = std::make_unique<ActiveListenerDetails>();
55:   if (config.internalListenerConfig().has_value()) {
56:     // Ensure the this ConnectionHandlerImpl link to the thread local registry. Ideally this step
57:     // should be done only once. However, an extra phase and interface is overkill.
58:     Network::InternalListenerRegistry& internal_listener_registry =
59:         config.internalListenerConfig()->internalListenerRegistry();
60:     Network::LocalInternalListenerRegistry* local_registry =
61:         internal_listener_registry.getLocalRegistry();
62:     RELEASE_ASSERT(local_registry != nullptr, "Failed to get local internal listener registry.");
63:     local_registry->setInternalListenerManager(*this);
64:     if (overridden_listener.has_value()) {
65:       if (auto iter = listener_map_by_tag_.find(overridden_listener.value());
66:           iter != listener_map_by_tag_.end()) {
67:         iter->second->invokeListenerMethod(
68:             [&config](Network::ConnectionHandler::ActiveListener& listener) {
69:               listener.updateListenerConfig(config);
70:             });
71:         return;
72:       }
73:       IS_ENVOY_BUG("unexpected");
74:     }
75:     auto internal_listener =
76:         local_registry->createActiveInternalListener(*this, config, dispatcher());
77:     // TODO(soulxu): support multiple internal addresses in listener in the future.
78:     ASSERT(config.listenSocketFactories().size() == 1);
79:     details->addActiveListener(
80:         config, config.listenSocketFactories()[0]->localAddress(), listener_reject_fraction_,
81:         disable_listeners_, std::move(internal_listener),
82:         config.shouldBypassOverloadManager() ? null_overload_manager_ : overload_manager_);
83:   } else if (config.listenSocketFactories()[0]->socketType() == Network::Socket::Type::Stream) {
84:     auto overload_state =
85:         config.shouldBypassOverloadManager()
86:             ? (null_overload_manager_
87:                    ? makeOptRef(null_overload_manager_->getThreadLocalOverloadState())
88:                    : absl::nullopt)
89:             : (overload_manager_ ? makeOptRef(overload_manager_->getThreadLocalOverloadState())
90:                                  : absl::nullopt);
91:     for (auto& socket_factory : config.listenSocketFactories()) {
92:       auto address = socket_factory->localAddress();
93:       // worker_index_ doesn't have a value on the main thread for the admin server.
94:       details->addActiveListener(
95:           config, address, listener_reject_fraction_, disable_listeners_,
96:           std::make_unique<ActiveTcpListener>(
97:               *this, config, runtime, random,
98:               socket_factory->getListenSocket(worker_index_.has_value() ? *worker_index_ : 0),
99:               address, config.connectionBalancer(*address), overload_state),
100:           config.shouldBypassOverloadManager() ? null_overload_manager_ : overload_manager_);
